import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.HG0H2VLS.js";const u=JSON.parse('{"title":"AiChatMinimised — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/templates/AiChatMinimised/AiChatMinimised.figma-notes.md","filePath":"public/demos/src/templates/AiChatMinimised/AiChatMinimised.figma-notes.md"}'),i={name:"public/demos/src/templates/AiChatMinimised/AiChatMinimised.figma-notes.md"};function r(s,t,n,c,l,h){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="aichatminimised-—-figma-notes" tabindex="-1">AiChatMinimised — Figma Notes <a class="header-anchor" href="#aichatminimised-—-figma-notes" aria-label="Permalink to &quot;AiChatMinimised — Figma Notes&quot;">​</a></h1><p><strong>Figma URL:</strong> <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2160-4810" target="_blank" rel="noreferrer">node 2160:4810</a></p><p><strong>Tier:</strong> Template</p><p>Floating popup chat widget (384px wide). Embeds the same chat UI as AiChat but in a fixed-position popup with drag, resize, and window controls.</p><hr><h2 id="how-it-differs-from-aichat" tabindex="-1">How it differs from AiChat <a class="header-anchor" href="#how-it-differs-from-aichat" aria-label="Permalink to &quot;How it differs from AiChat&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>AiChat</th><th>AiChatMinimised</th></tr></thead><tbody><tr><td>Layout</td><td>Full-page, responsive (fills viewport)</td><td>Fixed popup (384px × 668px), bottom-right corner</td></tr><tr><td>Sidebar</td><td>Inline at ≥1024px, overlay on mobile</td><td>Always overlay — slides in from left</td></tr><tr><td>Header</td><td>Default ChatHeader with admin controls</td><td>ChatHeader <code>--minimised</code> with window buttons (maximize + close)</td></tr><tr><td>Resize</td><td>Sidebar width on desktop (col-resize)</td><td>Popup height via top-edge handle (ns-resize)</td></tr><tr><td>Drag</td><td>None</td><td>Header acts as drag handle (<code>cursor: move</code>)</td></tr><tr><td>Responsiveness</td><td>Desktop ↔ mobile via media queries</td><td>Always mobile-width; CSS overrides pin all breakpoints</td></tr><tr><td>Border radius</td><td>None (edge-to-edge)</td><td><code>--ai-radius-xl</code> rounded corners</td></tr><tr><td>Shadow</td><td>Sidebar only (mobile open state)</td><td><code>--ai-shadow-lg</code> on popup container</td></tr><tr><td>Sidebar logo</td><td>Visible</td><td>Hidden</td></tr><tr><td>Sidebar search</td><td>Visible</td><td>Hidden</td></tr><tr><td>Admin controls</td><td>Visible at xl breakpoint</td><td>Not included</td></tr><tr><td>Max height</td><td>None (full viewport)</td><td><code>calc(100vh - spacing-6 × 2)</code>, min 320px</td></tr></tbody></table><hr><h2 id="css-override-strategy" tabindex="-1">CSS override strategy <a class="header-anchor" href="#css-override-strategy" aria-label="Permalink to &quot;CSS override strategy&quot;">​</a></h2><h3 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h3><p>The 384px popup lives on a <strong>desktop viewport</strong>, so <code>min-width: 640px</code> media queries in child components (ChatMain, SourcesCarousel, MessageInput, etc.) fire — incorrectly upgrading font sizes, grid columns, layout directions, and spacing to desktop values inside a mobile-width container.</p><h3 id="the-fix" tabindex="-1">The fix <a class="header-anchor" href="#the-fix" aria-label="Permalink to &quot;The fix&quot;">​</a></h3><p>Every desktop escalation is pinned back to its mobile base value using scoped overrides under <code>.ai-chat-min</code>. These are <strong>not new styles</strong> — they repeat the component&#39;s own mobile/base values, scoped to override the desktop media query.</p><h3 id="chatmain-overrides" tabindex="-1">ChatMain overrides <a class="header-anchor" href="#chatmain-overrides" aria-label="Permalink to &quot;ChatMain overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th><th>Desktop value blocked</th></tr></thead><tbody><tr><td><code>.chat-main__initial-inner</code></td><td>gap, padding</td><td><code>spacing-6</code>, <code>spacing-8 0</code></td><td>spacing-5, spacing-8 spacing-6</td></tr><tr><td><code>.chat-main__intro</code></td><td>gap, padding</td><td><code>spacing-3</code>, <code>0 spacing-5 0</code></td><td>spacing-5, 0 0 spacing-5</td></tr><tr><td><code>.chat-main__title</code></td><td>font-size, line-height</td><td><code>font-fixed-xl</code>, <code>leading-lg</code></td><td>font-fixed-3xl, leading-xl</td></tr><tr><td><code>.chat-main__subtitle</code></td><td>font-size</td><td><code>font-fixed-xs</code></td><td>font-fixed-sm / font-fixed-md</td></tr><tr><td><code>.chat-main__input-wrap</code></td><td>padding</td><td><code>0 spacing-5</code></td><td>0</td></tr><tr><td><code>.chat-main__suggestions</code></td><td>grid-template-columns, gap, padding</td><td><code>repeat(2, 1fr)</code>, <code>spacing-4</code>, <code>0 spacing-5</code></td><td>repeat(3, 1fr), spacing-5, 0</td></tr><tr><td><code>.chat-main__container</code></td><td>padding</td><td><code>spacing-6</code></td><td>spacing-8 spacing-6</td></tr><tr><td><code>.chat-main__response</code></td><td>font-size</td><td><code>font-fixed-xs</code></td><td>font-fluid-sm</td></tr><tr><td><code>.chat-main__response code</code></td><td>font-size</td><td><code>font-fixed-xxs</code></td><td>font-fixed-xs</td></tr><tr><td><code>.chat-main__input</code></td><td>padding</td><td><code>0 spacing-2</code></td><td>0</td></tr><tr><td><code>.chat-main__processing .skeletons</code></td><td>margin-top</td><td><code>spacing-6</code></td><td>spacing-8</td></tr><tr><td><code>.chat-main__processing .answer</code></td><td>margin-top, font-size</td><td><code>spacing-6</code>, <code>font-fixed-xs</code></td><td>spacing-7, font-fluid-sm</td></tr></tbody></table><h3 id="sourcescarousel-overrides" tabindex="-1">SourcesCarousel overrides <a class="header-anchor" href="#sourcescarousel-overrides" aria-label="Permalink to &quot;SourcesCarousel overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.sources-card</code></td><td>flex</td><td>Mobile 1.5-card width</td></tr><tr><td><code>.sources-card__inner</code></td><td>flex-direction, gap</td><td><code>column</code>, <code>spacing-3</code></td></tr><tr><td><code>.sources-card__thumb</code></td><td>order</td><td><code>0</code> (thumb first)</td></tr><tr><td><code>.sources-carousel</code></td><td>padding</td><td><code>0</code></td></tr><tr><td><code>.sources-carousel__nav</code></td><td>display</td><td><code>none</code> (arrows hidden)</td></tr></tbody></table><h3 id="sourceslink-overrides" tabindex="-1">SourcesLink overrides <a class="header-anchor" href="#sourceslink-overrides" aria-label="Permalink to &quot;SourcesLink overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.sources-link</code></td><td>max-width</td><td><code>100%</code> (uncapped)</td></tr></tbody></table><h3 id="chatresponsetable-overrides" tabindex="-1">ChatResponseTable overrides <a class="header-anchor" href="#chatresponsetable-overrides" aria-label="Permalink to &quot;ChatResponseTable overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.chat-response-table</code></td><td>font-size</td><td><code>font-fixed-xs</code></td></tr><tr><td><code>.chat-response-table th</code></td><td>font-size</td><td><code>font-fixed-xxs</code></td></tr></tbody></table><h3 id="suggestedquestion-overrides" tabindex="-1">SuggestedQuestion overrides <a class="header-anchor" href="#suggestedquestion-overrides" aria-label="Permalink to &quot;SuggestedQuestion overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.suggested-question [data-lucide]</code></td><td>width, height</td><td><code>icon-size-sm</code></td></tr><tr><td><code>.suggested-question__text</code></td><td>font-size, line-height</td><td><code>font-fixed-xxs</code>, <code>leading-xs</code></td></tr><tr><td><code>.suggested-question__subtext</code></td><td>display</td><td><code>none</code> (hidden)</td></tr></tbody></table><h3 id="workingintro-overrides" tabindex="-1">WorkingIntro overrides <a class="header-anchor" href="#workingintro-overrides" aria-label="Permalink to &quot;WorkingIntro overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.working-intro</code></td><td>gap</td><td><code>spacing-1</code></td></tr><tr><td><code>.working-intro__title-row</code></td><td>flex-direction, align-items, gap</td><td><code>column</code>, <code>flex-start</code>, <code>spacing-3</code></td></tr><tr><td><code>.working-intro__title</code></td><td>font-size</td><td><code>font-fixed-sm</code></td></tr><tr><td><code>.working-intro__subtitle</code></td><td>font-size</td><td><code>font-fixed-xs</code></td></tr></tbody></table><h3 id="messagebubble-overrides" tabindex="-1">MessageBubble overrides <a class="header-anchor" href="#messagebubble-overrides" aria-label="Permalink to &quot;MessageBubble overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.msg-bubble</code></td><td>padding-left</td><td><code>spacing-8</code></td></tr><tr><td><code>.msg-bubble__text</code></td><td>font-size</td><td><code>font-fixed-xs</code></td></tr></tbody></table><h3 id="messageinput-overrides" tabindex="-1">MessageInput overrides <a class="header-anchor" href="#messageinput-overrides" aria-label="Permalink to &quot;MessageInput overrides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Selector</th><th>Property</th><th>Value pinned</th></tr></thead><tbody><tr><td><code>.msg-input__box</code></td><td>padding</td><td><code>spacing-5</code></td></tr><tr><td><code>.msg-input__textarea</code></td><td>font-size</td><td><code>font-fixed-xs</code></td></tr></tbody></table><hr><h2 id="unique-features" tabindex="-1">Unique features <a class="header-anchor" href="#unique-features" aria-label="Permalink to &quot;Unique features&quot;">​</a></h2><ul><li><strong>Drag:</strong> Header (<code>cursor: move</code>) acts as drag surface; buttons retain <code>cursor: pointer</code></li><li><strong>Height resize:</strong> Top-edge handle (<code>cursor: ns-resize</code>), 6px hit area</li><li><strong>Panel height:</strong> Controlled via <code>--_panel-height</code> CSS custom property (default 668px)</li><li><strong>Transition suppression:</strong> <code>.ai-chat-min--no-transition</code> disables all transitions during drag/resize</li><li><strong>Close state:</strong> <code>.ai-chat-min--hidden</code> hides the entire widget (<code>display: none</code>)</li><li><strong>Overflow:</strong> <code>overflow: clip</code> on container for rounded corner clipping</li></ul><hr><h2 id="dark-mode" tabindex="-1">Dark mode <a class="header-anchor" href="#dark-mode" aria-label="Permalink to &quot;Dark mode&quot;">​</a></h2><ul><li><strong>Scrollbar colors:</strong> Custom <code>color-mix()</code> overrides for both light and dark themes, blending <code>--ai-surface-primary</code> with blue (light) or white (dark) at different ratios for track and thumb</li><li><strong>Tertiary button hover:</strong> <code>[data-theme=&quot;dark&quot;] .ai-chat-min .btn--tertiary:hover</code> uses <code>--ai-surface-minimal</code></li></ul><hr><h2 id="component-structure" tabindex="-1">Component structure <a class="header-anchor" href="#component-structure" aria-label="Permalink to &quot;Component structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.ai-chat-min (fixed position popup, data-surface=&quot;chat&quot;)</span></span>
<span class="line"><span>├── .ai-chat-min__resize-handle (top-edge, ns-resize)</span></span>
<span class="line"><span>├── ChatHeader --minimised (drag handle)</span></span>
<span class="line"><span>│   ├── Sidebar toggle button</span></span>
<span class="line"><span>│   ├── Assistant selector</span></span>
<span class="line"><span>│   ├── Maximize button</span></span>
<span class="line"><span>│   └── Close button</span></span>
<span class="line"><span>└── .ai-chat-min__main</span></span>
<span class="line"><span>    ├── .ai-chat-min__overlay (sidebar backdrop)</span></span>
<span class="line"><span>    ├── .ai-chat-min__sidebar (absolute, transform slide-in)</span></span>
<span class="line"><span>    │   └── ChatSidebar (logo + search hidden)</span></span>
<span class="line"><span>    └── ChatMain (all breakpoints pinned to mobile)</span></span>
<span class="line"><span>        ├── Initial view (welcome + suggestions)</span></span>
<span class="line"><span>        ├── Processing view (WorkingIntro + SourcesCarousel + Skeleton)</span></span>
<span class="line"><span>        ├── Response view (MessageBubble + prose + QuickLinks + ChatResponseTable)</span></span>
<span class="line"><span>        └── Footer (fade gradient + MessageInput)</span></span></code></pre></div><hr><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Composes <strong>ChatHeader</strong> (<code>src/patterns/ChatHeader/</code>) — <code>--minimised</code> variant</li><li>Composes <strong>ChatMain</strong> (<code>src/patterns/ChatMain/</code>)</li><li>Composes <strong>ChatSidebar</strong> (<code>src/patterns/ChatSidebar/</code>)</li><li>Inherits all ChatMain sub-dependencies: SuggestedQuestion, MessageBubble, MessageInput, WorkingIntro, SourcesCarousel, Skeleton, Button, Tooltip, QuickLinks, SourcesLink, ChatResponseTable</li></ul><hr><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>CSS class</th></tr></thead><tbody><tr><td>Popup container</td><td><code>.ai-chat-min</code></td></tr><tr><td>Top resize handle</td><td><code>.ai-chat-min__resize-handle</code></td></tr><tr><td>Sidebar overlay</td><td><code>.ai-chat-min__overlay</code></td></tr><tr><td>Sidebar wrapper</td><td><code>.ai-chat-min__sidebar</code></td></tr><tr><td>Main content area</td><td><code>.ai-chat-min__main</code></td></tr><tr><td>Hidden state</td><td><code>.ai-chat-min--hidden</code></td></tr><tr><td>Sidebar open state</td><td><code>.ai-chat-min--sidebar-open</code></td></tr><tr><td>Drag transition lock</td><td><code>.ai-chat-min--no-transition</code></td></tr><tr><td>Resize active</td><td><code>.ai-chat-min--resizing</code></td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Popup background</td><td><code>--ai-surface-primary</code> (via <code>data-surface=&quot;chat&quot;</code>)</td></tr><tr><td>Popup border radius</td><td><code>--ai-radius-xl</code></td></tr><tr><td>Popup shadow</td><td><code>--ai-shadow-lg</code></td></tr><tr><td>Popup width</td><td><code>--ai-size-7</code> (384px)</td></tr><tr><td>Popup min-height</td><td>320px</td></tr><tr><td>Max width</td><td><code>calc(100vw - spacing-5 × 2)</code></td></tr><tr><td>Max height</td><td><code>calc(100vh - spacing-6 × 2)</code></td></tr><tr><td>Resize handle hover bg</td><td><code>--ai-border-secondary</code></td></tr><tr><td>Sidebar shadow (open)</td><td><code>4px 4px 6px rgba(0,0,0,0.1)</code></td></tr></tbody></table>`,47)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
